@keyframes qi-addons-for-elementor-fade-in { 
  0% { opacity: 0; visibility: hidden; z-index: 102; }
  100% { opacity: 1; visibility: visible; z-index: 102; }
}
@keyframes qi-addons-for-elementor-fade-out { 
  0% { opacity: 1; visibility: visible; z-index: 102; }
  100% { opacity: 0; visibility: hidden; z-index: 0; }
}
@keyframes qodef-animate-underline-from-left { 
  0% { transform: scaleX(1); transform-origin: right center; }
  37% { transform: scaleX(0); transform-origin: right center; }
  38% { transform: scaleX(0); transform-origin: left center; }
  100% { transform: scaleX(1); transform-origin: left center; }
}
@keyframes qodef-animate-underline-from-right { 
  0% { transform: scaleX(1); transform-origin: left center; }
  37% { transform: scaleX(0); transform-origin: left center; }
  38% { transform: scaleX(0); transform-origin: right center; }
  100% { transform: scaleX(1); transform-origin: right center; }
}
@keyframes qodef-animate-underline-multiline { 
  0% { background-size: 100% 87%; background-position-x: right; }
  38% { background-size: 0px 87%; background-position-x: right; }
  39% { background-size: 0px 87%; background-position-x: left; }
  100% { background-size: 100% 87%; background-position-x: left; }
}
@keyframes qodef-animate-highlight { 
  0% { background-size: 0px 100%; background-position-x: left; }
  100% { background-size: 100% 100%; background-position-x: left; }
}
.qodef-qi-clear::after, .qodef-qi-clear::before { content: ""; display: table; table-layout: fixed; }
.qodef-qi-clear::after { clear: both; }
.qodef-category-separator::after { content: ","; margin-right: 5px; }
.qodef-shortcode h1 a, .qodef-shortcode h2 a, .qodef-shortcode h3 a, .qodef-shortcode h4 a, .qodef-shortcode h5 a, .qodef-shortcode h6 a { font-family: inherit; font-size: inherit; font-weight: inherit; font-style: inherit; line-height: inherit; letter-spacing: inherit; text-transform: inherit; color: inherit; }
.qodef-custom-text-underline-draw a { position: relative; color: currentcolor; }
.qodef-custom-text-underline-draw a::after { content: ""; position: absolute; bottom: 3px; left: 0px; width: 100%; height: 1px; background-color: currentcolor; backface-visibility: hidden; }
